async function adminCreateUploadFolder(){ const name=(document.getElementById('newUploadFolderName')?.value||'').trim(); if(!name){ toast('Isi nama folder terlebih dahulu'); return; } toast('Membuat folder...'); try{ await apiCall('adminCreateUploadFolder',{name}); toast('Folder upload berhasil dibuat'); document.getElementById('newUploadFolderName').value=''; adminRefreshUploadFolders(); refreshUploadFolders(); }catch(err){ modalShow({title:'Gagal buat folder', body:escapeHtml(err?.message||err)}); }}
async function adminRefreshUploadFolders(){ const status=document.getElementById('adminUploadStatus'); if(status) status.textContent='Memuat daftar folder upload...'; try{ const res=await apiCall('adminListUploadFolders',{}); const rows=res?.list||[]; if(status) status.textContent=`Total folder: ${rows.length}`; renderAdminUploadFolders(rows); refreshUploadFolders(); }catch(err){ if(status) status.textContent='Error: ' + (err?.message||err); }}
function renderAdminUploadFolders(list){ const box=document.getElementById('adminUploadFoldersTable'); if(!box) return; if(!list?.length){ box.innerHTML='<div class="hint">Belum ada folder upload.</div>'; return; } let html='<table><tr><th>Nama Folder</th><th>Folder ID</th><th>Dibuat</th><th>Link</th><th>Aksi</th></tr>'; list.forEach(x=>{ html += `<tr><td>${escapeHtml(x.name||'')}</td><td>${escapeHtml(x.folderId||'')}</td><td>${escapeHtml(x.created||'')}</td><td><a href="${x.url}" target="_blank">Buka Folder</a></td><td><button type="button" class="danger" style="margin-top:0; padding:6px 10px;" onclick="adminDeleteUploadFolder('${String(x.folderId||'').replace(/'/g,"\\'")}')">Hapus</button></td></tr>`; }); html+='</table>'; box.innerHTML=html; }
