async function adminRefreshLogs(){ const status=document.getElementById('adminLogsStatus'); if(status) status.textContent='Memuat log aktivitas...'; try{ const res=await apiCall('adminListLogs',{limit:500}); const rows=res?.list||[]; if(status) status.textContent=`Total log tampil: ${rows.length}`; renderAdminLogs(rows); }catch(err){ if(status) status.textContent='Error: ' + (err?.message||err); }}
function renderAdminLogs(list){ const box=document.getElementById('adminLogsTable'); if(!box) return; if(!list?.length){ box.innerHTML='<div class="hint">Belum ada log aktivitas.</div>'; return; } let html='<table><tr><th>Waktu</th><th>User</th><th>Role</th><th>Aksi</th><th>Detail</th><th>Hapus</th></tr>'; list.forEach(x=>{ html += `<tr><td>${escapeHtml(x.time||'')}</td><td>${escapeHtml((x.nama||'') + ' (' + (x.nip||'') + ')')}</td><td>${escapeHtml(x.role||'')}</td><td>${escapeHtml(x.action||'')}</td><td style="max-width:420px; white-space:pre-wrap;">${escapeHtml(x.detail||'')}</td><td><button type="button" class="danger" style="margin-top:0; padding:6px 10px;" onclick="adminDeleteLog(${Number(x.rowNum||0)})">Hapus</button></td></tr>`; }); html+='</table>'; box.innerHTML=html; }
