function adminClearLogs(){ modalShow({title:'Konfirmasi', body:'Hapus semua log aktivitas?', actions:[{label:'Batal',kind:'secondary'},{label:'Hapus Semua',kind:'danger',onClick: async ()=>{ toast('Menghapus semua log...'); try{ await apiCall('adminClearLogs',{}); toast('Semua log berhasil dihapus'); adminRefreshLogs(); }catch(err){ modalShow({title:'Gagal', body:escapeHtml(err?.message||err)}); } }}]}); }

function registerPwa(){ if(isStandaloneMode()){ setInstallButtonVisible(false); return; } setInstallButtonVisible(true); if(!('serviceWorker' in navigator)) return; window.addEventListener('beforeinstallprompt', e=>{ e.preventDefault(); deferredInstallPrompt=e; setInstallButtonVisible(true); toast('Aplikasi siap di-install');}); window.addEventListener('appinstalled', ()=>{ deferredInstallPrompt=null; setInstallButtonVisible(false); toast('Aplikasi berhasil di-install');}); navigator.serviceWorker.register('/sw.js').catch(err=>console.warn('SW gagal:', err)); }
async function installPwa(){ if(isStandaloneMode()){ toast('Aplikasi sudah terpasang'); return; } if(deferredInstallPrompt){ try{ deferredInstallPrompt.prompt(); await deferredInstallPrompt.userChoice; }catch(e){ console.warn(e); } finally { deferredInstallPrompt=null; } return; } modalShow({title:'Pasang Aplikasi', body:`Install otomatis belum tersedia dari browser ini.<br><br><b>Di Chrome Android:</b><br>1. Tekan menu <b>⋮</b><br>2. Pilih <b>Tambahkan ke layar utama</b> atau <b>Install app</b><br>3. Lalu konfirmasi pemasangan`}); }

window.addEventListener('load', ()=>{
  setInstallButtonVisible(!isStandaloneMode());
  bindLoginEnterBehavior();
  window.addEventListener('online', updateNetworkBanner); window.addEventListener('offline', updateNetworkBanner);
  registerPwa(); updateNetworkBanner(); bindLocalAutosave();
  document.getElementById('loginView')?.classList.add('hidden'); document.getElementById('appView')?.classList.add('hidden');
  document.getElementById('btnInstallPwa')?.addEventListener('click', installPwa);
  document.getElementById('btnLogin')?.addEventListener('click', e=>{e.preventDefault(); doLogin();});
  document.getElementById('btnForgot')?.addEventListener('click', e=>{e.preventDefault(); openForgot();});
  document.getElementById('btnRegister')?.addEventListener('click', e=>{e.preventDefault(); openRegister();});
  document.getElementById('btnLogout')?.addEventListener('click', doLogout);
  document.querySelectorAll('.tab[data-tab]').forEach(el=>el.addEventListener('click', ()=>showTab(el.getAttribute('data-tab'))));
  document.getElementById('btnPreview')?.addEventListener('click', generatePreview);
  document.getElementById('btnDownload')?.addEventListener('click', downloadPdf);
  document.getElementById('btnDownloadExcel')?.addEventListener('click', downloadExcel);
  document.getElementById('btnPrint')?.addEventListener('click', printPreview);
  document.getElementById('btnPreviewMobile')?.addEventListener('click', generatePreview);
  document.getElementById('btnDownloadMobile')?.addEventListener('click', downloadPdf);
  document.getElementById('btnRefreshDrafts')?.addEventListener('click', refreshDrafts);
  document.getElementById('btnSaveDraft')?.addEventListener('click', saveDraft);
  document.getElementById('btnLoadDraft')?.addEventListener('click', loadDraft);
  document.getElementById('btnDeleteDraft')?.addEventListener('click', deleteDraft);
  document.getElementById('btnRefreshFiles')?.addEventListener('click', refreshFiles);
  document.getElementById('btnOpenFolder')?.addEventListener('click', openFolder);
  document.getElementById('btnUploadLhk')?.addEventListener('click', uploadLhk);
  document.getElementById('btnChangePass')?.addEventListener('click', changePassword);
  document.getElementById('btnChangeEmail')?.addEventListener('click', changeEmail);
  document.getElementById('btnAdminRefreshNotifications')?.addEventListener('click', ()=>{adminRefreshNotifications(); adminRefreshNotificationsQuick();});
  document.getElementById('btnAdminClearNotifications')?.addEventListener('click', adminClearNotifications);
  document.getElementById('btnAdminRefreshOnlineUsers')?.addEventListener('click', adminRefreshOnlineUsers);
  document.getElementById('btnAdminLoadUsers')?.addEventListener('click', adminLoadUsers);
  document.getElementById('btnAdminCreateUser')?.addEventListener('click', adminCreateUser);
  document.getElementById('btnAdminSaveUploadRoot')?.addEventListener('click', adminSaveUploadRoot);
  document.getElementById('btnAdminCreateUploadFolder')?.addEventListener('click', adminCreateUploadFolder);
  document.getElementById('btnAdminRefreshUploadFolders')?.addEventListener('click', adminRefreshUploadFolders);
  document.getElementById('btnAdminRefreshLogs')?.addEventListener('click', adminRefreshLogs);
  document.getElementById('btnAdminClearLogs')?.addEventListener('click', adminClearLogs);
  document.addEventListener('keydown', e=>{ if(e.key==='Escape'){ const m=document.getElementById('modal'); if(m && !m.classList.contains('hidden')) modalHide(); }});
  bindColorPreview('colorHeader','previewColorHeader'); bindColorPreview('colorDateCol','previewColorDateCol'); bindColorPreview('colorOffRow','previewColorOffRow');
  tryAutoLogin();
});
